class Solution {
    public String robotWithString(String s) {
        StringBuilder sb = new StringBuilder();
        int n = s.length();
        char[] chars = s.toCharArray();
        int[] minRight = new int[n];
        minRight[n - 1] = s.charAt(n - 1);
        for (int i = n - 2; i >= 0; i--) {
            minRight[i] = Math.min(minRight[i + 1], chars[i]);
        }
        StringBuilder t = new StringBuilder();
        for (int i = 0; i < n; i++) {
            t.append(chars[i]);
            if (t.length() > 0 && (i == n - 1 || t.charAt(t.length() - 1) <= minRight[i + 1])) {
                sb.append(t.charAt(t.length() - 1));
                t.deleteCharAt(t.length() - 1);
            }
        }
        return sb.toString();
    }
}
